use packed_simd::f64x4;

fn add_vectors(a: &[f64], b: &[f64]) -> Vec<f64> {
  let len = a.len();
  let mut result = vec![0.0; len];

  let f4_len = (len / 4) * 4;
  for i in (0..f4_len).step_by(4) {
    let fa = f64x4::from_slice_unaligned(&a[i..i+4]);
    let fb = f64x4::from_slice_unaligned(&b[i..i+4]);
    let sum = fa + fb;
    sum.store_unaligned(&mut result[i..i+4]);
  }

  // Handle remainder manually if necessary
  for i in f4_len..len {
    result[i] = a[i] + b[i];
  }
  result
}
